import React, { useState, useEffect } from 'react';
import { View, Text, Image, FlatList, StyleSheet, Alert, ActivityIndicator } from 'react-native';
import { useAppStore } from '../../store/useAppStore';
import TvFocusable from '../../components/tv/TvFocusable';
import { db } from '../../config/firebase';
import { doc, getDoc } from 'firebase/firestore';

// ─── Avatares de Unsplash (fotos reales cinematográficas) ─────────────────────
const DEFAULT_AVATARS = [
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
  'data:image/jpeg;base64,',
];

export default function TvUserProfileScreen({ currentTab }: any) {
  const { userAvatar, setUserAvatar, currentProfile, watchHistory, logout } = useAppStore();
  const [hovered, setHovered] = useState<string | null>(null);
  const [avatars, setAvatars] = useState<string[]>(DEFAULT_AVATARS);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    const fetchAvatars = async () => {
      try {
        const snap = await getDoc(doc(db, 'settings', 'avatars'));
        if (mounted && snap.exists()) {
          const data = snap.data();
          if (data.list && Array.isArray(data.list) && data.list.length > 0) {
            setAvatars(data.list);
          }
        }
      } catch (error) {
        console.error("Error fetching avatars:", error);
      } finally {
        if (mounted) setLoading(false);
      }
    };
    fetchAvatars();
    return () => { mounted = false; };
  }, []);

  const displayAvatar = hovered ?? userAvatar ?? avatars[0];
  const moviesWatched = watchHistory.filter(h => h.item?.type === 'movie').length;

  const handleClearHistory = () =>
    Alert.alert('Vaciar Historial', '¿Borrar todo el historial?', [
      { text: 'Cancelar', style: 'cancel' },
      { text: 'Borrar', style: 'destructive', onPress: () => { } },
    ]);

  return (
    <View style={s.root}>
      {/* Glow morado fondo */}
      <View style={s.glow} pointerEvents="none" />

      {/* ─── COLUMNA IZQUIERDA ────────────────────────────────────────── */}
      <View style={s.left}>

        {/* Avatar */}
        <View style={s.avatarRing}>
          <Image source={{ uri: displayAvatar }} style={s.avatarImg} />
        </View>

        {/* Nombre */}
        <Text style={s.name}>{currentProfile?.name ?? 'Eliseo'}</Text>
        <Text style={s.role}>PREMIUM MEMBER</Text>

        {/* Stats */}
        <View style={s.stats}>
          <View style={s.stat}>
            <Text style={s.statN}>{moviesWatched}</Text>
            <Text style={s.statL}>PELÍCULAS</Text>
          </View>
          <View style={s.statDivider} />
          <View style={s.stat}>
            <Text style={s.statN}>{watchHistory.length}</Text>
            <Text style={s.statL}>HISTORIAL</Text>
          </View>
        </View>

        {/* Botones */}
        <View style={s.buttons}>
          <ActionBtn label="Cambiar Avatar" icon="✏️" onPress={() => { }} />
          <ActionBtn label="Vaciar Historial" icon="🗑️" onPress={handleClearHistory} />
          <ActionBtn label="Cerrar Sesión" icon="↪️" danger onPress={() => logout()} />
        </View>
      </View>

      {/* ─── COLUMNA DERECHA ─────────────────────────────────────────── */}
      <View style={s.right}>
        <Text style={s.rightTitle}>Choose Avatar</Text>
        <Text style={s.rightSub}>PERSONALIZE YOUR PORTAL</Text>

        {loading ? (
          <ActivityIndicator size="large" color="#7c3aed" style={{ marginTop: 50 }} />
        ) : (
          <FlatList
            data={avatars}
            horizontal
            keyExtractor={(_, i) => String(i)}
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={s.grid}
            renderItem={({ item }) => {
              const active = userAvatar === item;
              return (
                <TvFocusable
                  onPress={() => setUserAvatar(item)}
                  onFocus={() => setHovered(item)}
                  onBlur={() => setHovered(null)}
                  borderWidth={0}
                  scaleTo={1.1}
                  style={s.cardWrap}
                >
                  {(focused: boolean) => (
                    <View style={[s.card, focused && s.cardFocused, active && !focused && s.cardActive]}>
                      <Image source={{ uri: item }} style={s.cardImg} />
                      {!focused && <View style={s.cardOverlay} />}
                      {active && (
                        <View style={s.badge}>
                          <Text style={s.badgeText}>ACTIVE</Text>
                        </View>
                      )}
                    </View>
                  )}
                </TvFocusable>
              );
            }}
          />
        )}

        <Text style={s.hint}>{'<  '}Deslizá con el mando para navegar{'  >'}</Text>
      </View>
    </View>
  );
}

// ─── Botón de acción lateral ──────────────────────────────────────────────────
function ActionBtn({ label, icon, onPress, danger = false }: any) {
  return (
    <TvFocusable onPress={onPress} borderWidth={0} scaleTo={1.04} style={{ borderRadius: 10, marginBottom: 10 }}>
      {(focused: boolean) => (
        <View style={[s.btn,
        focused && danger && s.btnDanger,
        focused && !danger && s.btnFocused,
        ]}>
          <Text style={[s.btnLabel, danger && !focused && { color: '#EF4444' }]}>{label}</Text>
          <Text style={{ fontSize: 16 }}>{icon}</Text>
        </View>
      )}
    </TvFocusable>
  );
}

